<?php require_once 'includes/auth.php'; require_login(); $user=current_user(); $id=intval($_GET['id']??0); $stmt=$pdo->prepare('SELECT * FROM events WHERE id=?'); $stmt->execute([$id]); $event=$stmt->fetch(); if(!$event) die('Event not found'); $att_stmt=$pdo->prepare('SELECT * FROM attendance WHERE event_id=? AND user_id=?'); $att_stmt->execute([$id,$user['id']]); $attended=$att_stmt->fetch(); $fb_stmt=$pdo->prepare('SELECT f.*,u.name FROM feedback f JOIN users u ON u.id=f.user_id WHERE f.event_id=?'); $fb_stmt->execute([$id]); $feedbacks=$fb_stmt->fetchAll(); include 'includes/header.php'; ?><h2><?=htmlspecialchars($event['title'])?></h2><p><?=nl2br(htmlspecialchars($event['description']))?></p><p><strong>When:</strong> <?=$event['date']?> | <strong>Venue:</strong> <?=htmlspecialchars($event['venue'])?></p><?php if($attended): ?><p><strong>You marked attendance at <?= $attended['timestamp'] ?></strong></p><?php else: ?><form id='attendForm' method='post' action='attend.php'><input type='hidden' name='event_id' value='<?= $event['id'] ?>'><button type='submit'>Mark Attendance</button></form><?php endif; ?><h3>Give Feedback</h3><form method='post' action='feedback.php'><input type='hidden' name='event_id' value='<?= $event['id'] ?>'><label>Emoji<select name='emoji'><option value='😀'>😀</option><option value='🙂'>🙂</option><option value='😐'>😐</option><option value='😔'>😔</option><option value='😡'>😡</option></select></label><label>Comment<textarea name='comment'></textarea></label><button type='submit'>Submit Feedback</button></form><h3>Feedback</h3><?php if($feedbacks): ?><ul><?php foreach($feedbacks as $f): ?><li><?=htmlspecialchars($f['name'])?> — <?= $f['emoji'] ?> — <?=htmlspecialchars($f['comment'])?> — <?= $f['sentiment'] ?></li><?php endforeach; ?></ul><?php else: ?><p>No feedback yet.</p><?php endif; include 'includes/footer.php'; ?>